import { HttpClient } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from '@angular/forms';
import { AlertService } from 'src/app/core/services/alert.service';
import { ClientService } from 'src/app/core/services/client.service';
import { EnvService } from 'src/app/core/services/env.service';
import { InputMaskingService } from 'src/app/core/services/input-masking.service';
import { ClientLimit } from 'src/app/views/Models/Client/ClientInfoData';
import { SearchResult } from 'src/app/views/Models/References/SearchResult';

@Component({
  selector: 'app-edit-client-limit',
  templateUrl: './edit-client-limit.page.html',
  styleUrls: ['./edit-client-limit.page.scss'],
})
export class EditClientLimitPage implements OnInit {
  showLoader: boolean = false;
  isSearching: boolean = true;
  clientInfo: SearchResult;
  isSubmitted: boolean = false;
  isUpdating: boolean = false;
  isReportForm: boolean = false;
  initialSearchType: string = "1";
  selectedClient: ClientLimit;
  disabled: boolean = false;
  ClientForm: FormGroup = this.formBuilder.group({
    client_name: [""],
    client_code: [""],
    no_conc_loans: ["", [Validators.required]],
    cr_limit_total: ["", [Validators.required]],
  });
  constructor(
    private formBuilder: FormBuilder,
    private clientService: ClientService,
    public inputMaskingService: InputMaskingService,
    private alertServices: AlertService,
    private http: HttpClient,
    private env: EnvService,
  ) { }

  ngOnInit() {
  }
  async clientSelected(event: SearchResult): Promise<void> {
    this.selectedClient = await this.clientService
      .GetClientLimit(event.client_key);
    this.ClientForm.patchValue({
      client_name: this.selectedClient.client_name,
      client_code: this.selectedClient.org_branch_code+'/'+this.selectedClient.client_code,
      no_conc_loans: this.selectedClient.no_conc_loans,
      cr_limit_total: this.selectedClient.cr_limit_total,
    });
    this.isSearching = false;
    this.isReportForm = true;
    this.isUpdating= true;
  }
  backToSearch(): void {
    this.clientInfo = null;
    this.isSearching = true;
    this.isReportForm = false;
    this.isUpdating = false;
    this.selectedClient = null;
    this.ClientForm.reset();
  }
  submitUpdate() { 
    this.showLoader = true;
    if (this.ClientForm.valid) {
      this.http
        .post(this.env.API_URL + "api/ClientRegistration/GetClientLimitUpdate", {
          client_key: this.selectedClient.client_key,
          cr_limit_princ: this.ClientForm.value.cr_limit_total.toString(),
          cr_limit_total: this.ClientForm.value.cr_limit_total.toString(),
          no_conc_loans: this.ClientForm.value.no_conc_loans.toString(),
          uuc: this.selectedClient.uuc,
        })
        .subscribe({
          next: (data) => {
            this.showLoader = false;
            this.alertServices.showAlertConfirm(" تم التعديل بنجاح", true);
          },
          error: (err) => {
            console.log(err);
            this.alertServices.showAlertError(err.error, false);
            this.showLoader = false;
          },
        });
    }
    else {
      this.alertServices.showAlertError(" يجب ادخال القيمة", false);
      this.showLoader = false;
    
    }
  }
}
